import { useState } from 'react';
import axios from 'axios';

export default function Status() {
  const [id, setId] = useState("");
  const [data, setData] = useState(null);

  const fetchStatus = async () => {
    try {
      const res = await axios.get(`http://localhost:5000/applications/${id}`);
      setData(res.data);
    } catch (err) {
      alert("Application not found");
    }
  };

  return (
    <div className="container">
      <div className="card">
        <h2>Track Application Status</h2>

        <input
          placeholder="Enter Application ID"
          value={id}
          onChange={(e) => setId(e.target.value)}
        />

        <button onClick={fetchStatus}>Check Status</button>

        {data && (
          <div style={{ marginTop: "20px" }}>
            <h3>Application ID: {data.application_id}</h3>
            <p><strong>Documents:</strong> {data.documents_submitted ? "Yes" : "No"}</p>
            <p><strong>Police Verification:</strong> {data.police_verification}</p>

            {/* FINAL STATUS */}
            <p>
              <strong>Status: </strong>
              <span className={`status ${
                data.status === "Pending" ? "pending" :
                data.status === "Verified" ? "verified" :
                "generated"
              }`}>
                {data.status}
              </span>
            </p>
          </div>
        )}
      </div>
    </div>
  );
}
